import './UserProfile.css';export default function UserProfile({username,followers,profilePic}){return(<div className='card profile shadow'><div className='card-body text-center'><img src={profilePic} alt='profile'/><h3 className='mt-3'>{username}</h3><p>Followers : {followers}</p><button className='btn btn-danger'>Follow</button></div></div>)} UserProfile.defaultProps={followers:0,profilePic:'https://cdn-icons-png.flaticon.com/512/149/149071.png'};